function Chart({ width, height }) {
  // New array allocated on every render:
  const style = { width, height }; // ← new reference each time

  // New function allocated on every render:
  const handleClick = () => console.log('clicked'); // ← new ref each time

  useEffect(() => {
    applyStyle(style);
  }, [style]); // re-runs on every render — style is always new!

  useEffect(() => {
    document.addEventListener('click', handleClick);
    return () => document.removeEventListener('click', handleClick);
  }, [handleClick]); // re-registers on every render!
}

// ✗ Object dep — re-runs every render
useEffect(() => {
  applyStyle({ width, height });
}, [{ width, height }]);

// ✓ Primitive deps — re-runs only when width or height changes
useEffect(() => {
  applyStyle({ width, height });
}, [width, height]);

function Dashboard({ userId, role, region }) {
  const queryConfig = useMemo(
    () => ({ userId, role, region }),
    [userId, role, region] // recompute only when these change
  );

  useEffect(() => {
    analytics.setContext(queryConfig);
  }, [queryConfig]); // stable — only changes when userId/role/region change
}

function SearchWidget({ query, pageSize }) {
  useEffect(() => {
    // params is built inside — not a dep, never causes over-firing
    const params = new URLSearchParams({ q: query, limit: pageSize });
    fetch(`/api/search?${params}`).then(...);
  }, [query, pageSize]); // only the primitives
}

// Parent: stabilise the callback reference
function Parent({ userId }) {
  const onData = useCallback((data) => {
    console.log('received data for', userId, data);
  }, [userId]); // only recreated when userId changes

  return <DataFetcher onData={onData} />;
}

// Child: can safely use onData as a dep
function DataFetcher({ onData }) {
  useEffect(() => {
    const sub = stream.subscribe(onData);
    return () => sub.unsubscribe();
  }, [onData]); // re-subscribes only when userId changes (via onData)
}

function Timer({ label }) {
  // New function reference on every render
  function tick() {
    console.log(label, Date.now());
  }

  useEffect(() => {
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [tick]); // re-registers interval on every render!
}

// Fix A: useCallback
const tick = useCallback(() => {
  console.log(label, Date.now());
}, [label]); // stable reference; only changes when label changes

// Fix B: move the function inside the effect
useEffect(() => {
  function tick() { console.log(label, Date.now()); }
  const id = setInterval(tick, 1000);
  return () => clearInterval(id);
}, [label]); // function is no longer a dep

function TagFilter({ tags }) {
  // 'tags' is a prop array — its reference changes
  // when the parent re-renders, even if contents are identical

  useEffect(() => {
    applyTagFilter(tags);
  }, [tags]); // may fire every render if parent doesn't memoize!

  // Fix A: use a stable derived value
  const tagKey = tags.join(','); // stable string if tags haven't changed
  useEffect(() => {
    applyTagFilter(tags);
  }, [tagKey]); // only re-runs when the set of tags changes

  // Fix B: require parent to memoize tags
  // const tags = useMemo(() => ['react', 'hooks'], []); // in parent
}

// Debugging: which dep triggered the re-run?
const prevDeps = useRef({ config, onSelect });
useEffect(() => {
  const prev = prevDeps.current;
  if (!Object.is(prev.config, config)) console.log('config changed', prev.config, '->', config);
  if (!Object.is(prev.onSelect, onSelect)) console.log('onSelect changed');
  prevDeps.current = { config, onSelect };
}, [config, onSelect]);

// Libraries like 'why-did-you-render' automate this pattern
// and highlight which dep changed between renders in DevTools.

// ✗ Infinite loop
function DataPanel({ source }) {
  const [data, setData] = useState(null);

  // BAD: 'source' is an object passed from the parent
  // Parent renders → new source ref → effect fires → fetch → setState
  // → re-render → parent renders → new source ref → effect fires ...
  useEffect(() => {
    fetch(source.url).then(r => r.json()).then(setData);
  }, [source]); // source = { url, headers } is a new object every parent render
}

// ✓ Fix: use stable primitive
useEffect(() => {
  fetch(source.url).then(r => r.json()).then(setData);
}, [source.url]); // string — stable between renders if URL hasn't changed

// ✗ New object on every provider render
function AppProvider({ children }) {
  const [user, setUser] = useState(null);
  return (
    <UserContext.Provider value={{ user, setUser }}>
      {children}
    </UserContext.Provider>
  ); // { user, setUser } is a new object on every render!
}

// ✓ Fix: stabilise the context value with useMemo
function AppProvider({ children }) {
  const [user, setUser] = useState(null);
  const value = useMemo(() => ({ user, setUser }), [user]);
  return (
    <UserContext.Provider value={value}>{children}</UserContext.Provider>
  ); // value ref only changes when user changes
}

// ✗ Hook returns new object every render
function useWindowSize() {
  const [w, setW] = useState(window.innerWidth);
  const [h, setH] = useState(window.innerHeight);
  useEffect(() => {
    const fn = () => { setW(window.innerWidth); setH(window.innerHeight); };
    window.addEventListener('resize', fn);
    return () => window.removeEventListener('resize', fn);
  }, []);
  return { width: w, height: h }; // ← new object each render
}

// Consumer:
function Layout() {
  const size = useWindowSize();
  useEffect(() => {
    recalculateLayout(size);
  }, [size]); // fires every render because size is always new!
}

// ✓ Fix: destructure at the call site
const { width, height } = useWindowSize();
useEffect(() => {
  recalculateLayout(width, height);
}, [width, height]); // stable primitives

// If 'options' is an unstable object, the callback is also unstable
const handleData = useCallback((data) => {
  process(data, options); // options dep
}, [options]); // useCallback re-creates fn whenever options changes

// And if handleData is an effect dep:
useEffect(() => {
  stream.subscribe(handleData);
  return () => stream.unsubscribe(handleData);
}, [handleData]); // still over-fires if options is unstable!

// The full fix: stabilise at the root
// options must be stable (useMemo / primitives) before useCallback can be stable.

// React 19 experimental — stabilises 'onData' without useCallback
import { experimental_useEffectEvent as useEffectEvent } from 'react';

function DataStream({ channelId, onData }) {
  // onData is extracted into an 'effect event' — not a dep
  const handleData = useEffectEvent(onData);

  useEffect(() => {
    const sub = subscribe(channelId, handleData);
    return () => sub.unsubscribe();
  }, [channelId]); // only channelId is a dep; handleData is always current
}

// Pre-React 19 equivalent (ref pattern):
const onDataRef = useRef(onData);
useEffect(() => { onDataRef.current = onData; }); // keep ref current
useEffect(() => {
  const sub = subscribe(channelId, (data) => onDataRef.current(data));
  return () => sub.unsubscribe();
}, [channelId]);
